/**
 * Specialist — local agent instances (same machine, stdio AcpClient).
 *
 * Config lives at MEMORY_DIR/config/specialists.json (fallback: AGENT_CONFIG_DIR).
 * Each entry defines a named specialist with its own CLI harness, working
 * directory, and user-data-dir for skill isolation.
 *
 * Flow:
 *   1. Bridge intercepts RELAY_DELEGATE token
 *   2. If target matches a specialist name → dispatch here (not relay)
 *   3. Spawn or reuse an AcpClient for that specialist
 *   4. Inject goal prompt → collect result → return ResultPayload
 */
import { readFile } from "node:fs/promises";
import { appendFile, mkdir } from "node:fs/promises";
import path from "node:path";
import { AcpClient, type AcpClientOptions, type SessionUpdate } from "./acpClient.js";
import type { DelegatePayload, ResultPayload } from "./relay.js";
import { config, resolveBridgeConfigPath } from "./config.js";
import { buildSpecialistPreamble, getSpecialistScope } from "./specialist-create.js";
import { logEvent } from "./event-log.js";
import { runEnrichment } from "./enrichment.js";
import { isEmbedModelReady } from "./embed-router.js";
import { isWikiRetrievalReady } from "./wiki-retrieval.js";
import { isMemoryRecallReady } from "./memory-recall.js";
import { registerTask, updateTask, completeTask } from "./status-store.js";
import { broadcastSSE } from "./status-server.js";
import { verifySpecialistOutput, buildRetryPrompt } from "./verifier.js";

// ─── Config types ──────────────────────────────────────────────────────────

export interface SpecialistHarness {
  command: string;
  args: string[];
}

export interface SpecialistEntry {
  /** Display/lookup name — must match the target in RELAY_DELEGATE token. */
  name: string;
  /** CLI command + args to spawn the agent. */
  harness: SpecialistHarness;
  /** Working directory for the specialist session. */
  cwd: string;
  /** Extra env vars merged into the specialist process. */
  env?: Record<string, string>;
  /** MCP servers to inject via ACP session/new. */
  mcpServers?: any[];
  /**
   * Model pin applied via ACP `session/set_config_option` after session/new.
   * Only the Claude adapter honours this (Kiro/Codex reject → best-effort
   * swallowed in AcpClient). Kiro/Codex pin model via harness args instead.
   */
  model?: string;
  /** Effort pin (Claude adapter only). Applied after model — see AcpClient. */
  effort?: string;
  /** Permission policy for agent-initiated requests — see AcpClientOptions. */
  permissionMode?: "grant-all" | "readonly";
  /** Max turns before force-stopping a delegation. Default 15. */
  maxTurns?: number;
  /** Timeout (ms) for the entire delegation. Default 1800000 (30min). */
  timeoutMs?: number;
}

export type SpecialistsConfig = SpecialistEntry[];

// ─── Config loading ────────────────────────────────────────────────────────

let loadedConfig: SpecialistsConfig = [];
let configPath = "";
let loadedAgentConfigDir = "";

export function getSpecialists(): SpecialistsConfig {
  return loadedConfig;
}

/** Check if a target name matches a local specialist. */
export function isLocalSpecialist(target: string): boolean {
  return loadedConfig.some((s) => s.name === target);
}

/**
 * /status command handler — shows active task status.
 * Opens local Electron window + replies text summary.
 */
import { Context } from "grammy";
import { spawn } from "child_process";
import * as path from "path";
import { listActiveTasks, listTasks, type TaskEntry } from "../status-store.js";
import { deps } from "./deps.js";

let electronProc: ReturnType<typeof spawn> | null = null;

export async function handleStatus(ctx: Context): Promise<void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;

  const active = listActiveTasks();

  // Always try to open/focus the Electron window
  openStatusWindow();

  if (active.length === 0) {
    const recent = listTasks().filter((t) => t.status !== "running").slice(-5);
    if (recent.length === 0) {
      await ctx.reply("目前沒有進行中或最近完成的任務。\n🖥 已開啟監控視窗");
    } else {
      const lines = recent.map((t) => formatTaskLine(t));
      await ctx.reply(`目前沒有進行中的任務。\n\n最近完成：\n${lines.join("\n")}\n\n🖥 已開啟監控視窗`);
    }
    return;
  }

  // Active tasks exist — show detailed status
  const lines = active.map((t) => formatTaskDetail(t));
  await ctx.reply(`⚡ ${active.length} 個任務進行中：\n\n${lines.join("\n\n")}\n\n🖥 已開啟監控視窗`);
}

function openStatusWindow(): void {
  // If already running, don't spawn again
  if (electronProc && !electronProc.killed) return;

  const bridgeDir = path.resolve(path.dirname(new URL(import.meta.url).pathname).replace(/^\/([A-Z]:)/, "$1"), "../..");
  const appDir = path.join(bridgeDir, "status-app");
  try {
    electronProc = spawn("npx", ["electron", appDir], {
      stdio: "ignore",
      detached: true,
      shell: true,
      cwd: bridgeDir,
    });
    electronProc.unref();
    electronProc.on("exit", () => { electronProc = null; });
    electronProc.on("error", (err) => {
      console.warn("[status] Electron spawn error (electron not installed?):", err.message);
      electronProc = null;
    });
  } catch (e) {
    console.warn("[status] Failed to open Electron window:", e);
  }
}

function formatTaskDetail(t: TaskEntry): string {
  const elapsed = Math.round((Date.now() - new Date(t.startTime).getTime()) / 1000);
  const mins = Math.floor(elapsed / 60);
  const secs = elapsed % 60;
  const time = mins > 0 ? `${mins}m${secs}s` : `${secs}s`;
  const target = t.specialist ?? t.peer ?? "unknown";
  const turns = t.turns ? `Turn ${t.turns}` : "";
  const checkpoint = t.checkpoint?.currentStep ? `Step: ${t.checkpoint.currentStep}` : "";
  const lastOut = t.lastOutput ? `\n💬 ${t.lastOutput.slice(0, 100)}` : "";
  const info = [turns, checkpoint].filter(Boolean).join(" | ");
  return `🔄 [${target}] ${time}${info ? `\n📋 ${info}` : ""}\n🎯 ${t.goal.slice(0, 80)}${lastOut}`;
}

function formatTaskLine(t: TaskEntry): string {
  const icon = t.status === "running" ? "🔄" : t.status === "done" ? "✅" : t.status === "failed" ? "❌" : t.status === "timeout" ? "⏰" : "🚫";
  const elapsed = t.endTime
    ? Math.round((new Date(t.endTime).getTime() - new Date(t.startTime).getTime()) / 1000)
    : Math.round((Date.now() - new Date(t.startTime).getTime()) / 1000);
  const target = t.specialist ?? t.peer ?? "";
  const turns = t.turns ? ` T${t.turns}` : "";
  return `${icon} [${target}] ${t.goal.slice(0, 50)}${turns} (${elapsed}s)`;
}

/**
 * Status Store — in-memory task registry for /status monitoring.
 * Tracks specialist, relay_delegate, and parallel_delegate tasks.
 */

export interface TaskCheckpoint {
  currentStep: string;
  totalSteps?: number;
  completedSteps?: number;
}

export type TaskType = "specialist" | "relay_delegate" | "parallel_delegate" | "goal";
export type TaskStatus = "running" | "done" | "failed" | "timeout" | "cancelled";

export interface TaskEntry {
  taskId: string;
  type: TaskType;
  specialist?: string;
  peer?: string;
  goal: string;
  status: TaskStatus;
  startTime: string;
  endTime?: string;
  checkpoint?: TaskCheckpoint;
  lastOutput?: string;
  error?: string;
  turns?: number;
}

const tasks = new Map<string, TaskEntry>();

export function registerTask(entry: Omit<TaskEntry, "status" | "startTime">): TaskEntry {
  const task: TaskEntry = {
    ...entry,
    status: "running",
    startTime: new Date().toISOString(),
  };
  tasks.set(task.taskId, task);
  return task;
}

export function updateTask(taskId: string, patch: Partial<Pick<TaskEntry, "checkpoint" | "lastOutput" | "turns">>): void {
  const t = tasks.get(taskId);
  if (!t) return;
  Object.assign(t, patch);
}

export function completeTask(taskId: string, status: TaskStatus, opts?: { error?: string; lastOutput?: string }): void {
  const t = tasks.get(taskId);
  if (!t) return;
  t.status = status;
  t.endTime = new Date().toISOString();
  if (opts?.error) t.error = opts.error;
  if (opts?.lastOutput) t.lastOutput = opts.lastOutput;
}

export function cancelTask(taskId: string): boolean {
  const t = tasks.get(taskId);
  if (!t || t.status !== "running") return false;
  t.status = "cancelled";
  t.endTime = new Date().toISOString();
  return true;
}

export function getTask(taskId: string): TaskEntry | undefined {
  return tasks.get(taskId);
}

export function listTasks(filter?: { status?: TaskStatus }): TaskEntry[] {
  const all = [...tasks.values()];
  if (filter?.status) return all.filter((t) => t.status === filter.status);
  return all;
}

export function listActiveTasks(): TaskEntry[] {
  return listTasks({ status: "running" });
}

/** Prune completed tasks older than maxAge ms (default 1h). */
export function prune(maxAgeMs = 3_600_000): number {
  const cutoff = Date.now() - maxAgeMs;
  let removed = 0;
  for (const [id, t] of tasks) {
    if (t.status !== "running" && t.endTime && new Date(t.endTime).getTime() < cutoff) {
      tasks.delete(id);
      removed++;
    }
  }
  return removed;
}

