 4→ */
 5→
 6→export interface TaskCheckpoint {
 7→  currentStep: string;
 8→  totalSteps?: number;
 9→  completedSteps?: number;
10→}
11→
12→export type TaskType = "specialist" | "relay_delegate" | "parallel_delegate" | "goal";
13→export type TaskStatus = "running" | "done" | "failed" | "timeout" | "cancelled";
14→
15→export interface TaskEntry {
16→  taskId: string;
17→  type: TaskType;
18→  specialist?: string;
19→  peer?: string;
20→  goal: string;
21→  status: TaskStatus;
22→  startTime: string;
23→  endTime?: string;
24→  checkpoint?: TaskCheckpoint;
25→  lastOutput?: string;
26→  error?: string;
27→  turns?: number;
28→}
29→
30→const tasks = new Map<string, TaskEntry>();
31→
32→export function registerTask(entry: Omit<TaskEntry, "status" | "startTime">): TaskEntry {
33→  const task: TaskEntry = {
34→    ...entry,
35→    status: "running",
36→    startTime: new Date().toISOString(),
37→  };
38→  tasks.set(task.taskId, task);
39→  return task;
40→}
41→
42→export function updateTask(taskId: string, patch: Partial<Pick<TaskEntry, "checkpoint" | "lastOutput" | "turns">>): void {
43→  const t = tasks.get(taskId);
44→  if (!t) return;
45→  Object.assign(t, patch);
46→}
47→
48→export function completeTask(taskId: string, status: TaskStatus, opts?: { error?: string; lastOutput?: string }): void {
49→  const t = tasks.get(taskId);
50→  if (!t) return;
51→  t.status = status;
52→  t.endTime = new Date().toISOString();
53→  if (opts?.error) t.error = opts.error;
54→  if (opts?.lastOutput) t.lastOutput = opts.lastOutput;
55→}
56→
57→export function cancelTask(taskId: string): boolean {
58→  const t = tasks.get(taskId);
59→  if (!t || t.status !== "running") return false;
60→  t.status = "cancelled";
61→  t.endTime = new Date().toISOString();
62→  return true;
63→}
64→
65→export function getTask(taskId: string): TaskEntry | undefined {
66→  return tasks.get(taskId);
67→}
68→
69→export function listTasks(filter?: { status?: TaskStatus }): TaskEntry[] {
70→  const all = [...tasks.values()];
71→  if (filter?.status) return all.filter((t) => t.status === filter.status);
72→  return all;
73→}
74→
75→export function listActiveTasks(): TaskEntry[] {
76→  return listTasks({ status: "running" });
77→}
78→
79→/** Prune completed tasks older than maxAge ms (default 1h). */
80→export function prune(maxAgeMs = 3_600_000): number {
81→  const cutoff = Date.now() - maxAgeMs;
82→  let removed = 0;
83→  for (const [id, t] of tasks) {
84→    if (t.status !== "running" && t.endTime && new Date(t.endTime).getTime() < cutoff) {
85→      tasks.delete(id);
86→      removed++;
87→    }
88→  }
89→  return removed;
90→}
