const { app, BrowserWindow } = require("electron");
const path = require("path");

// Use separate user-data-dir to avoid conflict with desktop-pet Electron instance
app.setPath("userData", path.join(app.getPath("appData"), "kiro-status-app"));

const STATUS_URL = `http://localhost:${process.env.STATUS_PORT || 3847}`;
let win = null;

function createWindow() {
  win = new BrowserWindow({
    width: 480,
    height: 600,
    title: "Status Monitor",
    autoHideMenuBar: true,
    webPreferences: { contextIsolation: true, nodeIntegration: false },
  });
  win.loadURL(STATUS_URL);
  win.on("closed", () => { win = null; });
}

app.whenReady().then(createWindow);
app.on("window-all-closed", () => app.quit());

