/** Check if harness uses --agent flag (kiro-cli loads MCP servers from agent config). */
function harnessHasAgentFlag(entry: SpecialistEntry): boolean {
  return entry.harness.args.includes("--agent");
}

/**
 * Normalize stored MCP server configs into the ACP `session/new` schema.
 * The ACP SDK validates each server against zMcpServer: the stdio variant
 * requires `args` and `env` to be present, and `env` must be an ARRAY of
 * {name, value} — not the `{KEY: val}` object shape we store. HTTP/SSE
 * servers keep their `type` and get headers coerced to array form. Disabled
 * servers are dropped. Without this, session/new rejects with -32602.
 */
function toAcpMcpServers(servers: any[] | undefined): any[] | undefined {
  if (!Array.isArray(servers)) return undefined;
  const toArr = (env: any) =>
    Array.isArray(env)
      ? env
      : Object.entries(env ?? {}).map(([name, value]) => ({ name, value: String(value) }));
  return servers
    .filter((s) => s && !s.disabled)
    .map((s) => {
      if (s.type === "http" || s.type === "sse") {
        return {
          type: s.type,
          name: s.name,
          url: s.url,
          headers: Array.isArray(s.headers)
            ? s.headers
            : Object.entries(s.headers ?? {}).map(([name, value]) => ({ name, value: String(value) })),
        };
      }
      return {
        name: s.name,
        command: s.command,
        args: Array.isArray(s.args) ? s.args : [],
        env: toArr(s.env),
      };
    });
}

/** Expand ${MEMORY_DIR} / ${AGENT_CONFIG_DIR} / ${BRIDGE_DIR} in specialist config strings. */
function expandVars(entry: SpecialistEntry): SpecialistEntry {
  const vars: Record<string, string> = {
    MEMORY_DIR: config.memoryDir,
    AGENT_CONFIG_DIR: loadedAgentConfigDir,
    BRIDGE_DIR: path.resolve(config.sessionCwd),
  };
  const replace = (s: string) =>
    s.replace(/\$\{(\w+)\}/g, (_, k) => vars[k] ?? `\${${k}}`);
  return {
    ...entry,
    cwd: replace(entry.cwd),
    harness: { command: entry.harness.command, args: entry.harness.args.map(replace) },
    env: entry.env
      ? Object.fromEntries(Object.entries(entry.env).map(([k, v]) => [k, replace(v)]))
      : undefined,
  };
}

/** Load specialists.json from MEMORY_DIR/config (fallback: AGENT_CONFIG_DIR). Returns count loaded. */
export async function loadSpecialistsConfig(agentConfigDir: string): Promise<number> {
  loadedAgentConfigDir = agentConfigDir;
  configPath = resolveBridgeConfigPath("specialists.json", agentConfigDir);
  try {
    const raw = await readFile(configPath, "utf8");
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) {
      console.warn(`[specialist] ${configPath} is not an array, ignoring`);
      loadedConfig = [];
      return 0;
    }
    loadedConfig = (parsed as SpecialistsConfig).map(expandVars);
    console.log(`[specialist] loaded ${loadedConfig.length} specialist(s) from ${configPath}`);
    return loadedConfig.length;
  } catch (err: any) {
    if (err.code === "ENOENT") {
      console.log(`[specialist] no config at ${configPath} — feature disabled`);
    } else {
      console.warn(`[specialist] failed to load ${configPath}:`, err.message);
    }
    loadedConfig = [];
    return 0;
  }
}

// ─── Transcript persistence ────────────────────────────────────────────────

const transcriptDir = path.join(config.memoryDir, "sessions");

async function appendTranscript(name: string, role: "user" | "assistant", text: string): Promise<void> {
  const date = new Date().toISOString().slice(0, 10);
  const file = path.join(transcriptDir, `specialist-${name}-${date}.md`);
  await mkdir(transcriptDir, { recursive: true });
  const prefix = role === "user" ? "**User:**" : `**${name}:**`;
  const entry = `${prefix}\n${text}\n\n---\n\n`;
  await appendFile(file, entry, "utf8");
}

