/**
 * Status Server — lightweight HTTP API + Mini App for /status monitoring.
 * Independent server on STATUS_PORT (default 3847).
 */
import { createServer, type Server, type IncomingMessage, type ServerResponse } from "node:http";
import { readFile } from "node:fs/promises";
import path from "node:path";
import { listTasks, listActiveTasks, getTask, cancelTask } from "./status-store.js";

let httpServer: Server | undefined;

// SSE clients per taskId
const sseClients = new Map<string, Set<ServerResponse>>();

export function startStatusServer(port: number): void {
  if (httpServer) return;

  const staticDir = path.resolve(import.meta.dirname ?? ".", "..", "status-app");

  httpServer = createServer(async (req, res) => {
    // CORS
    res.setHeader("Access-Control-Allow-Origin", "*");
    res.setHeader("Access-Control-Allow-Methods", "GET, POST, OPTIONS");
    res.setHeader("Access-Control-Allow-Headers", "Content-Type");
    if (req.method === "OPTIONS") { res.writeHead(204); res.end(); return; }

    const url = new URL(req.url ?? "/", `http://localhost:${port}`);
    const p = url.pathname;

    // ─── API routes ──────────────────────────────────────────────────────
    if (p === "/api/status" && req.method === "GET") {
      const active = listActiveTasks();
      const recent = listTasks().filter((t) => t.status !== "running").slice(-10);
      json(res, { active, recent });
      return;
    }

    // SSE stream
    const streamMatch = p.match(/^\/api\/status\/([^/]+)\/stream$/);
    if (streamMatch && req.method === "GET") {
      const taskId = streamMatch[1];
      res.writeHead(200, {
        "Content-Type": "text/event-stream",
        "Cache-Control": "no-cache",
        "Connection": "keep-alive",
      });
      // Register client
      if (!sseClients.has(taskId)) sseClients.set(taskId, new Set());
      sseClients.get(taskId)!.add(res);
      // Send current status immediately
      const task = getTask(taskId);
      if (task) {
        sseSend(res, { type: "status", status: task.status, turns: task.turns });
      }
      req.on("close", () => {
        sseClients.get(taskId)?.delete(res);
        if (sseClients.get(taskId)?.size === 0) sseClients.delete(taskId);
      });
      return;
    }

    // Cancel
    const cancelMatch = p.match(/^\/api\/status\/([^/]+)\/cancel$/);
    if (cancelMatch && req.method === "POST") {
      const ok = cancelTask(cancelMatch[1]);
      if (!ok) json(res, { error: "cannot cancel" }, 400);
      else {
        broadcastSSE(cancelMatch[1], { type: "status", status: "cancelled" });
        json(res, { ok: true });
      }
      return;
    }

    // Single task
    const taskMatch = p.match(/^\/api\/status\/([^/]+)$/);
    if (taskMatch && req.method === "GET") {
      const task = getTask(taskMatch[1]);
      if (!task) json(res, { error: "not found" }, 404);
      else json(res, task);
      return;
    }

    // ─── Static files ────────────────────────────────────────────────────
    if (p === "/" || p === "/index.html") {
      try {
        const html = await readFile(path.join(staticDir, "index.html"), "utf8");
        res.writeHead(200, { "Content-Type": "text/html; charset=utf-8" });
        res.end(html);
      } catch {
        res.writeHead(500); res.end("index.html not found");
      }
      return;
    }

    json(res, { error: "not found" }, 404);
  });

  httpServer.listen(port, () => {
    console.log(`[status-server] listening on port ${port}`);
  });
}

export function stopStatusServer(): void {
  httpServer?.close();
  httpServer = undefined;
}

// ─── SSE broadcast ─────────────────────────────────────────────────────────

/** Broadcast an SSE event to all clients watching a task. */
export function broadcastSSE(taskId: string, data: Record<string, unknown>): void {
  const clients = sseClients.get(taskId);
  if (!clients || clients.size === 0) return;
  const payload = `data: ${JSON.stringify(data)}\n\n`;
  for (const res of clients) {
    res.write(payload);
  }
}

function sseSend(res: ServerResponse, data: Record<string, unknown>): void {
  res.write(`data: ${JSON.stringify(data)}\n\n`);
}

function json(res: ServerResponse, data: unknown, status = 200): void {
  res.writeHead(status, { "Content-Type": "application/json" });
  res.end(JSON.stringify(data));
}

/**
 * /status command handler — shows active task status.
 * Opens local Electron window + replies text summary.
 */
import { Context } from "grammy";
import { spawn } from "child_process";
import * as path from "path";
import { listActiveTasks, listTasks, type TaskEntry } from "../status-store.js";
import { deps } from "./deps.js";

let electronProc: ReturnType<typeof spawn> | null = null;

export async function handleStatus(ctx: Context): Promise<void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;

  const active = listActiveTasks();

  // Always try to open/focus the Electron window
  openStatusWindow();

  if (active.length === 0) {
    const recent = listTasks().filter((t) => t.status !== "running").slice(-5);
    if (recent.length === 0) {
      await ctx.reply("目前沒有進行中或最近完成的任務。\n🖥 已開啟監控視窗");
    } else {
      const lines = recent.map((t) => formatTaskLine(t));
      await ctx.reply(`目前沒有進行中的任務。\n\n最近完成：\n${lines.join("\n")}\n\n🖥 已開啟監控視窗`);
    }
    return;
  }

  // Active tasks exist — show detailed status
  const lines = active.map((t) => formatTaskDetail(t));
  await ctx.reply(`⚡ ${active.length} 個任務進行中：\n\n${lines.join("\n\n")}\n\n🖥 已開啟監控視窗`);
}

function openStatusWindow(): void {
  // If already running, don't spawn again
  if (electronProc && !electronProc.killed) return;

  const bridgeDir = path.resolve(path.dirname(new URL(import.meta.url).pathname).replace(/^\/([A-Z]:)/, "$1"), "../..");
  const appDir = path.join(bridgeDir, "status-app");
  try {
    electronProc = spawn("npx", ["electron", appDir], {
      stdio: "ignore",
      detached: true,
      shell: true,
      cwd: bridgeDir,
    });
    electronProc.unref();
    electronProc.on("exit", () => { electronProc = null; });
    electronProc.on("error", (err) => {
      console.warn("[status] Electron spawn error (electron not installed?):", err.message);
      electronProc = null;
    });
  } catch (e) {
    console.warn("[status] Failed to open Electron window:", e);
  }
}

function formatTaskDetail(t: TaskEntry): string {
  const elapsed = Math.round((Date.now() - new Date(t.startTime).getTime()) / 1000);
  const mins = Math.floor(elapsed / 60);
  const secs = elapsed % 60;
  const time = mins > 0 ? `${mins}m${secs}s` : `${secs}s`;
  const target = t.specialist ?? t.peer ?? "unknown";
  const turns = t.turns ? `Turn ${t.turns}` : "";
  const checkpoint = t.checkpoint?.currentStep ? `Step: ${t.checkpoint.currentStep}` : "";
  const lastOut = t.lastOutput ? `\n💬 ${t.lastOutput.slice(0, 100)}` : "";
  const info = [turns, checkpoint].filter(Boolean).join(" | ");
  return `🔄 [${target}] ${time}${info ? `\n📋 ${info}` : ""}\n🎯 ${t.goal.slice(0, 80)}${lastOut}`;
}

function formatTaskLine(t: TaskEntry): string {
  const icon = t.status === "running" ? "🔄" : t.status === "done" ? "✅" : t.status === "failed" ? "❌" : t.status === "timeout" ? "⏰" : "🚫";
  const elapsed = t.endTime
    ? Math.round((new Date(t.endTime).getTime() - new Date(t.startTime).getTime()) / 1000)
    : Math.round((Date.now() - new Date(t.startTime).getTime()) / 1000);
  const target = t.specialist ?? t.peer ?? "";
  const turns = t.turns ? ` T${t.turns}` : "";
  return `${icon} [${target}] ${t.goal.slice(0, 50)}${turns} (${elapsed}s)`;
}

