/**
 * Event Log — 狀態轉移持久化記錄
 * 
 * 可查、可審計、可回放。30 天滾動清理。
 */

import { appendFileSync, existsSync, readFileSync, writeFileSync, mkdirSync } from "fs";
import { dirname, join } from "path";
import { config } from "./config.js";

// ─── Types ─────────────────────────────────────────────────────────────────

export type EventType =
  | "session_start"
  | "session_end"
  | "goal_start"
  | "goal_step"
  | "goal_done"
  | "goal_cancel"
  | "specialist_spawn"
  | "specialist_done"
  | "moa_start"
  | "moa_done"
  | "moa_debate_start"
  | "moa_debate_done"
  | "moa_auto_trigger"
  | "moa_plan_exec"
  | "moa_plan_done"
  | "reaction_feedback"
  | "scheduler_fire"
  | "tool_call"
  | "orphan_flush"
  | "error";

export interface StateEvent {
  ts: string;
  type: EventType;
  chatId?: number;
  userId?: number;
  payload: Record<string, unknown>;
}

// ─── Config ────────────────────────────────────────────────────────────────

const EVENT_LOG_PATH = join(config.memoryDir, "events.jsonl");
const RETENTION_DAYS = 30;

// ─── Core Functions ────────────────────────────────────────────────────────

/**
 * 寫入一筆 event
 */
export function logEvent(
  type: EventType,
  payload: Record<string, unknown> = {},
  opts: { chatId?: number; userId?: number } = {}
): void {
  const event: StateEvent = {
    ts: new Date().toISOString(),
    type,
    ...opts,
    payload,
  };

  try {
    // 確保目錄存在
    const dir = dirname(EVENT_LOG_PATH);
    if (!existsSync(dir)) {
      mkdirSync(dir, { recursive: true });
    }

    appendFileSync(EVENT_LOG_PATH, JSON.stringify(event) + "\n", "utf-8");
  } catch (err) {
    // Event log 失敗不應該影響主流程
    console.error("[event-log] Failed to write event:", err);
  }
}

/**
 * 讀取最近 n 筆 events
 */
export function getRecentEvents(n: number = 50): StateEvent[] {
  if (!existsSync(EVENT_LOG_PATH)) return [];

  try {
    const content = readFileSync(EVENT_LOG_PATH, "utf-8");
    const lines = content.trim().split("\n").filter(Boolean);
    const events = lines
      .slice(-n)
      .map((line) => {
        try {
          return JSON.parse(line) as StateEvent;
        } catch {
          return null;
        }
      })
      .filter((e): e is StateEvent => e !== null);

    return events;
  } catch {
    return [];
  }
}

/**
 * 讀取特定類型的 events
 */
export function getEventsByType(type: EventType, n: number = 50): StateEvent[] {
  return getRecentEvents(n * 3).filter((e) => e.type === type).slice(-n);
}

/**
 * 讀取特定 chat 的 events
 */
export function getEventsByChat(chatId: number, n: number = 50): StateEvent[] {
  return getRecentEvents(n * 3).filter((e) => e.chatId === chatId).slice(-n);
}

/**
 * 滾動清理：刪除超過 RETENTION_DAYS 的 events
 * 
 * 建議在 /dream 時呼叫
 */
export function rotateEventLog(): { deleted: number; kept: number } {
  if (!existsSync(EVENT_LOG_PATH)) {
    return { deleted: 0, kept: 0 };
  }

  try {
    const content = readFileSync(EVENT_LOG_PATH, "utf-8");
    const lines = content.trim().split("\n").filter(Boolean);

    const cutoff = new Date();
    cutoff.setDate(cutoff.getDate() - RETENTION_DAYS);
    const cutoffStr = cutoff.toISOString();

    const kept: string[] = [];
    let deleted = 0;

    for (const line of lines) {
      try {
        const event = JSON.parse(line) as StateEvent;
        if (event.ts >= cutoffStr) {
          kept.push(line);
        } else {
          deleted++;
        }
      } catch {
        // 無法解析的行直接丟棄
        deleted++;
      }
    }

    writeFileSync(EVENT_LOG_PATH, kept.join("\n") + (kept.length ? "\n" : ""), "utf-8");

    return { deleted, kept: kept.length };
  } catch (err) {
    console.error("[event-log] Failed to rotate:", err);
    return { deleted: 0, kept: 0 };
  }
}

/**
 * 統計過去 days 天的 tool_call 使用次數，依工具名稱聚合。
 *
 * 回傳依使用次數由多到少排序的陣列；total 為總呼叫數、failed 為失敗數。
 */
export function getToolUsageStats(days: number = 7): {
  byTool: Array<{ name: string; total: number; failed: number }>;
  total: number;
  failed: number;
} {
  const cutoff = new Date();
  cutoff.setDate(cutoff.getDate() - days);
  const cutoffStr = cutoff.toISOString();

  const counts = new Map<string, { total: number; failed: number }>();
  let total = 0;
  let failed = 0;

  for (const e of getRecentEvents(10000)) {
    if (e.type !== "tool_call" || e.ts < cutoffStr) continue;
    const name = (e.payload?.name as string) ?? "tool";
    const isFail = e.payload?.status === "failed";
    const cur = counts.get(name) ?? { total: 0, failed: 0 };
    cur.total++;
    if (isFail) cur.failed++;
    counts.set(name, cur);
    total++;
    if (isFail) failed++;
  }

  const byTool = [...counts.entries()]
    .map(([name, v]) => ({ name, total: v.total, failed: v.failed }))
    .sort((a, b) => b.total - a.total);

  return { byTool, total, failed };
}

/**
 * 取得 event log 統計
 */
export function getEventLogStats(): {
  totalEvents: number;
  oldestEvent?: string;
  newestEvent?: string;
  byType: Record<string, number>;
} {
  const events = getRecentEvents(10000); // 讀取全部（最多 10000）

  if (events.length === 0) {
    return { totalEvents: 0, byType: {} };
  }

  const byType: Record<string, number> = {};
  for (const e of events) {
    byType[e.type] = (byType[e.type] || 0) + 1;
  }

  return {
    totalEvents: events.length,
    oldestEvent: events[0]?.ts,
    newestEvent: events[events.length - 1]?.ts,
    byType,
  };
}

/**
 * Specialist — local agent instances (same machine, stdio AcpClient).
 *
 * Config lives at MEMORY_DIR/config/specialists.json (fallback: AGENT_CONFIG_DIR).
 * Each entry defines a named specialist with its own CLI harness, working
 * directory, and user-data-dir for skill isolation.
 *
 * Flow:
 *   1. Bridge intercepts RELAY_DELEGATE token
 *   2. If target matches a specialist name → dispatch here (not relay)
 *   3. Spawn or reuse an AcpClient for that specialist
 *   4. Inject goal prompt → collect result → return ResultPayload
 */
import { readFile } from "node:fs/promises";
import { appendFile, mkdir } from "node:fs/promises";
import path from "node:path";
import { AcpClient, type AcpClientOptions, type SessionUpdate } from "./acpClient.js";
import type { DelegatePayload, ResultPayload } from "./relay.js";
import { config, resolveBridgeConfigPath } from "./config.js";
import { buildSpecialistPreamble, getSpecialistScope } from "./specialist-create.js";
import { logEvent } from "./event-log.js";
import { runEnrichment } from "./enrichment.js";
import { isEmbedModelReady } from "./embed-router.js";
import { isWikiRetrievalReady } from "./wiki-retrieval.js";
import { isMemoryRecallReady } from "./memory-recall.js";
import { registerTask, updateTask, completeTask } from "./status-store.js";
import { broadcastSSE } from "./status-server.js";
import { verifySpecialistOutput, buildRetryPrompt } from "./verifier.js";

// ─── Config types ──────────────────────────────────────────────────────────

import "dotenv/config";
import { accessSync, constants, existsSync, mkdirSync } from "node:fs";
import path from "node:path";
import ffmpegStatic from "ffmpeg-static";
import type { ProviderType } from "./provider/types.js";

function required(name: string): string {
  const v = process.env[name];
  if (!v || v.trim() === "") {
    throw new Error(`Missing required env var: ${name}`);
  }
  return v;
}

function parseCommand(raw: string): { command: string; args: string[] } {
  const parts = raw.trim().split(/\s+/);
  if (parts.length === 0) {
    throw new Error("ACP_AGENT_COMMAND is empty");
  }
  return { command: parts[0], args: parts.slice(1) };
}

function buildAgent(): { command: string; args: string[] } {
  const base = parseCommand(process.env.ACP_AGENT_COMMAND ?? "kiro-cli acp");
  const name = (process.env.ACP_AGENT_NAME ?? "").trim();
  if (name && !base.args.includes("--agent")) {
    base.args.push("--agent", name);
  }
  return base;
}

function configuredMemoryDir(): string {
  return path.resolve(
    process.env.MEMORY_DIR && process.env.MEMORY_DIR.trim() !== ""
      ? process.env.MEMORY_DIR
      : "F:\\AI\\AIMemory"
  );
}

