     1→/**
     2→ * Event Log — 狀態轉移持久化記錄
     3→ * 
     4→ * 可查、可審計、可回放。30 天滾動清理。
     5→ */
     6→
     7→import { appendFileSync, existsSync, readFileSync, writeFileSync, mkdirSync } from "fs";
     8→import { dirname, join } from "path";
     9→import { config } from "./config.js";
    10→
    11→// ─── Types ─────────────────────────────────────────────────────────────────
    12→
    13→export type EventType =
    14→  | "session_start"
    15→  | "session_end"
    16→  | "goal_start"
    17→  | "goal_step"
    18→  | "goal_done"
    19→  | "goal_cancel"
    20→  | "specialist_spawn"
    21→  | "specialist_done"
    22→  | "moa_start"
    23→  | "moa_done"
    24→  | "moa_debate_start"
    25→  | "moa_debate_done"
    26→  | "moa_auto_trigger"
    27→  | "moa_plan_exec"
    28→  | "moa_plan_done"
    29→  | "reaction_feedback"
    30→  | "scheduler_fire"
    31→  | "tool_call"
    32→  | "orphan_flush"
    33→  | "error";
    34→
    35→export interface StateEvent {
    36→  ts: string;
    37→  type: EventType;
    38→  chatId?: number;
    39→  userId?: number;
    40→  payload: Record<string, unknown>;
    41→}
    42→
    43→// ─── Config ────────────────────────────────────────────────────────────────
    44→
    45→const EVENT_LOG_PATH = join(config.memoryDir, "events.jsonl");
    46→const RETENTION_DAYS = 30;
    47→
    48→// ─── Core Functions ────────────────────────────────────────────────────────
    49→
    50→/**
    51→ * 寫入一筆 event
    52→ */
    53→export function logEvent(
    54→  type: EventType,
    55→  payload: Record<string, unknown> = {},
    56→  opts: { chatId?: number; userId?: number } = {}
    57→): void {
    58→  const event: StateEvent = {
    59→    ts: new Date().toISOString(),
    60→    type,
    61→    ...opts,
    62→    payload,
    63→  };
    64→
    65→  try {
    66→    // 確保目錄存在
    67→    const dir = dirname(EVENT_LOG_PATH);
    68→    if (!existsSync(dir)) {
    69→      mkdirSync(dir, { recursive: true });
    70→    }
    71→
    72→    appendFileSync(EVENT_LOG_PATH, JSON.stringify(event) + "\n", "utf-8");
    73→  } catch (err) {
    74→    // Event log 失敗不應該影響主流程
    75→    console.error("[event-log] Failed to write event:", err);
    76→  }
    77→}
    78→
    79→/**
    80→ * 讀取最近 n 筆 events
    81→ */
    82→export function getRecentEvents(n: number = 50): StateEvent[] {
    83→  if (!existsSync(EVENT_LOG_PATH)) return [];
    84→
    85→  try {
    86→    const content = readFileSync(EVENT_LOG_PATH, "utf-8");
    87→    const lines = content.trim().split("\n").filter(Boolean);
    88→    const events = lines
    89→      .slice(-n)
    90→      .map((line) => {
    91→        try {
    92→          return JSON.parse(line) as StateEvent;
    93→        } catch {
    94→          return null;
    95→        }
    96→      })
    97→      .filter((e): e is StateEvent => e !== null);
    98→
    99→    return events;
   100→  } catch {
   101→    return [];
   102→  }
   103→}
   104→
   105→/**
   106→ * 讀取特定類型的 events
   107→ */
   108→export function getEventsByType(type: EventType, n: number = 50): StateEvent[] {
   109→  return getRecentEvents(n * 3).filter((e) => e.type === type).slice(-n);
   110→}
   111→
   112→/**
   113→ * 讀取特定 chat 的 events
   114→ */
   115→export function getEventsByChat(chatId: number, n: number = 50): StateEvent[] {
   116→  return getRecentEvents(n * 3).filter((e) => e.chatId === chatId).slice(-n);
   117→}
   118→
   119→/**
   120→ * 滾動清理：刪除超過 RETENTION_DAYS 的 events
   121→ * 
   122→ * 建議在 /dream 時呼叫
   123→ */
   124→export function rotateEventLog(): { deleted: number; kept: number } {
   125→  if (!existsSync(EVENT_LOG_PATH)) {
   126→    return { deleted: 0, kept: 0 };
   127→  }
   128→
   129→  try {
   130→    const content = readFileSync(EVENT_LOG_PATH, "utf-8");
   131→    const lines = content.trim().split("\n").filter(Boolean);
   132→
   133→    const cutoff = new Date();
   134→    cutoff.setDate(cutoff.getDate() - RETENTION_DAYS);
   135→    const cutoffStr = cutoff.toISOString();
   136→
   137→    const kept: string[] = [];
   138→    let deleted = 0;
   139→
   140→    for (const line of lines) {
   141→      try {
   142→        const event = JSON.parse(line) as StateEvent;
   143→        if (event.ts >= cutoffStr) {
   144→          kept.push(line);
   145→        } else {
   146→          deleted++;
   147→        }
   148→      } catch {
   149→        // 無法解析的行直接丟棄
   150→        deleted++;
   151→      }
   152→    }
   153→
   154→    writeFileSync(EVENT_LOG_PATH, kept.join("\n") + (kept.length ? "\n" : ""), "utf-8");
   155→
   156→    return { deleted, kept: kept.length };
   157→  } catch (err) {
   158→    console.error("[event-log] Failed to rotate:", err);
   159→    return { deleted: 0, kept: 0 };
   160→  }
   161→}
   162→
   163→/**
   164→ * 統計過去 days 天的 tool_call 使用次數，依工具名稱聚合。
   165→ *
   166→ * 回傳依使用次數由多到少排序的陣列；total 為總呼叫數、failed 為失敗數。
   167→ */
   168→export function getToolUsageStats(days: number = 7): {
   169→  byTool: Array<{ name: string; total: number; failed: number }>;
   170→  total: number;
   171→  failed: number;
   172→} {
   173→  const cutoff = new Date();
   174→  cutoff.setDate(cutoff.getDate() - days);
   175→  const cutoffStr = cutoff.toISOString();
   176→
   177→  const counts = new Map<string, { total: number; failed: number }>();
   178→  let total = 0;
   179→  let failed = 0;
   180→
   181→  for (const e of getRecentEvents(10000)) {
   182→    if (e.type !== "tool_call" || e.ts < cutoffStr) continue;
   183→    const name = (e.payload?.name as string) ?? "tool";
   184→    const isFail = e.payload?.status === "failed";
   185→    const cur = counts.get(name) ?? { total: 0, failed: 0 };
   186→    cur.total++;
   187→    if (isFail) cur.failed++;
   188→    counts.set(name, cur);
   189→    total++;
   190→    if (isFail) failed++;
   191→  }
   192→
   193→  const byTool = [...counts.entries()]
   194→    .map(([name, v]) => ({ name, total: v.total, failed: v.failed }))
   195→    .sort((a, b) => b.total - a.total);
   196→
   197→  return { byTool, total, failed };
   198→}
   199→
   200→/**
   201→ * 取得 event log 統計
   202→ */
   203→export function getEventLogStats(): {
   204→  totalEvents: number;
   205→  oldestEvent?: string;
   206→  newestEvent?: string;
   207→  byType: Record<string, number>;
   208→} {
   209→  const events = getRecentEvents(10000); // 讀取全部（最多 10000）
   210→
   211→  if (events.length === 0) {
   212→    return { totalEvents: 0, byType: {} };
   213→  }
   214→
   215→  const byType: Record<string, number> = {};
   216→  for (const e of events) {
   217→    byType[e.type] = (byType[e.type] || 0) + 1;
   218→  }
   219→
   220→  return {
   221→    totalEvents: events.length,
   222→    oldestEvent: events[0]?.ts,
   223→    newestEvent: events[events.length - 1]?.ts,
   224→    byType,
   225→  };
   226→}
   227→
   228→
