```typescript
let factsCache: { ts: number; data: Map<string, Array<{ id: string; timestamp: string; text: string }>> } | null = null;
const FACTS_CACHE_TTL = 60_000;

async function loadFactsForSpecialist(name: string): Promise<{ totalCount: number; recentFacts: Array<{ id: string; timestamp: string; text: string }> }> {
  const now = Date.now();
  if (!factsCache || now - factsCache.ts > FACTS_CACHE_TTL) {
    factsCache = { ts: now, data: new Map() };
    const userId = (process.env.ALLOWED_USER_IDS ?? "").split(",")[0]?.trim();
    if (userId) {
      const shardDir = path.join(config.memoryDir, "facts_Topic", userId);
      try {
        const files = await readdir(shardDir);
        for (const file of files) {
          if (!file.endsWith(".md")) continue;
          const content = await readFile(path.join(shardDir, file), "utf8");
          const lines = content.split("\n").filter((l) => l.startsWith("- ["));
          for (const line of lines) {
            const idMatch = line.match(/\[([^\]]+)\]/);
            const tsMatch = line.match(/\[(\d{4}-\d{2}-\d{2}T[^\]]+)\]/);
            const textMatch = line.match(/\]\s+(.+)$/);
            if (!idMatch || !textMatch) continue;
            const fact = { id: idMatch[1], timestamp: tsMatch?.[1] ?? "", text: textMatch[1] };
            // Check all specialists
            for (const sp of getSpecialists()) {
              if (line.toLowerCase().includes(sp.name.toLowerCase())) {
                if (!factsCache.data.has(sp.name)) factsCache.data.set(sp.name, []);
                factsCache.data.get(sp.name)!.push(fact);
              }
            }
          }
        }
      } catch { /* shardDir may not exist */ }
    }
  }
  const facts = factsCache.data.get(name) ?? [];
  return { totalCount: facts.length, recentFacts: facts.slice(-5).reverse() };
}
