<script>
const API = location.origin;
const app = document.getElementById('app');
let pollTimer = null;
let currentRoute = null;
let eventSource = null;
let autoScroll = true;

// ─── Router ──────────────────────────────────────────────────────────────────
function navigate(hash) {
  location.hash = hash;
}

function getRoute() {
  const h = location.hash || '#/';
  const spMatch = h.match(/^#\/specialist\/(.+)$/);
  if (spMatch) return { page: 'specialist', name: decodeURIComponent(spMatch[1]) };
  const taskMatch = h.match(/^#\/task\/(.+)$/);
  if (taskMatch) return { page: 'task', taskId: decodeURIComponent(taskMatch[1]) };
  return { page: 'dashboard' };
}

window.addEventListener('hashchange', () => route());

function route() {
  stopPolling();
  if (eventSource) { eventSource.close(); eventSource = null; }
  const r = getRoute();
  currentRoute = r;
  if (r.page === 'dashboard') renderDashboard();
  else if (r.page === 'specialist') renderSpecialistDetail(r.name);
  else if (r.page === 'task') renderLiveView(r.taskId);
}

// ─── Dashboard ───────────────────────────────────────────────────────────────
async function renderDashboard() {
  app.innerHTML = '<div class="empty">載入中...</div>';
  try {
    const [statusRes, spRes] = await Promise.all([
      fetch(`${API}/api/status`).then(r => r.json()),
      fetch(`${API}/api/specialists`).then(r => r.json()),
    ]);
    paintDashboard(spRes, statusRes);
    startPolling(async () => {
      const [s, sp] = await Promise.all([
        fetch(`${API}/api/status`).then(r => r.json()),
        fetch(`${API}/api/specialists`).then(r => r.json()),
      ]);
      paintDashboard(sp, s);
    });
  } catch(e) {
    app.innerHTML = `<div class="empty">無法連線 API: ${esc(e.message)}</div>`;
  }
}

function paintDashboard(specialists, status) {
  let html = '';

  // Specialist cards
  html += '<div class="section-title">Specialists</div><div class="card-grid">';
  if (specialists.length === 0) {
    html += '<div class="empty">尚無 specialist 設定</div>';
  } else {
    html += specialists.map(sp => {
      const activeHtml = sp.activeTaskId
        ? `<div class="active-task" data-task="${esc(sp.activeTaskId)}">⚡ 執行中...</div>`
        : '';
      return `<div class="sp-card ${sp.status}" data-name="${esc(sp.name)}">
        <div class="name">${esc(sp.name)}</div>
        <div class="model">${esc(sp.model)}</div>
        <div class="status-row">
          <span class="badge ${sp.status}">${sp.status}</span>
          <span>${sp.recentTaskCount} tasks/7d</span>
        </div>
        ${activeHtml}
      </div>`;
    }).join('');
  }
  html += '</div>';

  // Active tasks
  if (status.active.length > 0) {
    html += '<div class="section-title">進行中</div><div class="task-list">';
    html += status.active.map(taskCard).join('');
    html += '</div>';
  }

  // Recent tasks
  if (status.recent.length > 0) {
    html += '<div class="section-title">最近完成</div><div class="task-list">';
    html += status.recent.map(taskCard).join('');
    html += '</div>';
  }

  if (specialists.length === 0 && status.active.length === 0 && status.recent.length === 0) {
    html = '<div class="empty">目前沒有任務</div>';
  }

  app.innerHTML = html;

  // Bind clicks
  app.querySelectorAll('.sp-card[data-name]').forEach(el => {
    el.addEventListener('click', (e) => {
      if (e.target.closest('.active-task')) {
        navigate('#/task/' + e.target.closest('.active-task').dataset.task);
        return;
      }
      navigate('#/specialist/' + el.dataset.name);
    });
  });
  app.querySelectorAll('.task[data-id]').forEach(el => {
    el.addEventListener('click', () => navigate('#/task/' + el.dataset.id));
  });
}

function taskCard(t) {
  const elapsed = t.endTime
    ? Math.round((new Date(t.endTime) - new Date(t.startTime)) / 1000)
    : Math.round((Date.now() - new Date(t.startTime)) / 1000);
  const target = t.specialist || t.peer || t.type;
  const turns = t.turns ? `T${t.turns}` : '';
  return `<div class="task ${t.status}" data-id="${esc(t.taskId)}">
    <div class="task-header">
      <span class="task-target">${esc(target)}</span>
      <span class="task-badge ${t.status}">${t.status}</span>
    </div>
    <div class="task-goal">${esc(t.goal)}</div>
    <div class="task-meta"><span>${elapsed}s</span><span>${turns}</span><span>${t.type}</span></div>
  </div>`;
}

// ─── Specialist Detail ───────────────────────────────────────────────────────
async function renderSpecialistDetail(name) {
  app.innerHTML = '<div class="empty">載入中...</div>';
  try {
    const detail = await fetch(`${API}/api/specialists/${encodeURIComponent(name)}`).then(r => r.json());
    if (detail.error) { app.innerHTML = `<div class="empty">找不到 ${esc(name)}</div>`; return; }
    paintSpecialistDetail(name, detail);
  } catch(e) {
    app.innerHTML = `<div class="empty">載入失敗: ${esc(e.message)}</div>`;
  }
}

function paintSpecialistDetail(name, detail) {
  const tabs = ['設定', 'Preamble', '歷史', '產出物', 'Facts'];
  let html = `<button class="back-btn" onclick="navigate('#/')">← Dashboard</button>`;
  html += `<h1><span class="dot" style="background:${detail.status === 'busy' ? 'var(--green)' : 'var(--muted)'}"></span> ${esc(name)}</h1>`;
  html += '<div class="tabs">';
  tabs.forEach((t, i) => {
    html += `<button class="tab${i === 0 ? ' active' : ''}" data-tab="${i}">${t}</button>`;
  });
  html += '</div>';

  // Tab 0: Config
  html += `<div class="tab-content active" data-panel="0">
    <table class="config-table">
      <tr><td>Harness</td><td>${esc(detail.harness.command + ' ' + detail.harness.args.join(' '))}</td></tr>
      <tr><td>Model</td><td>${esc(detail.model)}</td></tr>
      <tr><td>CWD</td><td>${esc(detail.cwd)}</td></tr>
      <tr><td>MaxTurns</td><td>${detail.maxTurns}</td></tr>
      <tr><td>Timeout</td><td>${Math.round(detail.timeoutMs / 60000)}m</td></tr>
      <tr><td>MCP</td><td>${detail.mcpServersFull.map(s => esc(s.name)).join(', ') || 'none'}</td></tr>
      ${detail.env ? `<tr><td>Env</td><td>${esc(JSON.stringify(detail.env))}</td></tr>` : ''}
    </table>
  </div>`;

  // Tab 1-4: lazy loaded
  for (let i = 1; i <= 4; i++) {
    html += `<div class="tab-content" data-panel="${i}"><div class="empty">點擊載入...</div></div>`;
  }

  app.innerHTML = html;

  // Tab switching
  app.querySelectorAll('.tab').forEach(btn => {
    btn.addEventListener('click', () => {
      app.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
      app.querySelectorAll('.tab-content').forEach(t => t.classList.remove('active'));
      btn.classList.add('active');
      const idx = btn.dataset.tab;
      const panel = app.querySelector(`[data-panel="${idx}"]`);
      panel.classList.add('active');
      // Lazy load
      if (idx === '1' && panel.querySelector('.empty')) loadPreamble(name, panel);
      if (idx === '2' && panel.querySelector('.empty')) loadHistory(name, panel);
      if (idx === '3' && panel.querySelector('.empty')) loadArtifacts(name, panel);
      if (idx === '4' && panel.querySelector('.empty')) loadFacts(name, panel);
    });
  });
}

async function loadPreamble(name, panel) {
  try {
    const r = await fetch(`${API}/api/specialists/${encodeURIComponent(name)}/preamble`);
    if (!r.ok) { panel.innerHTML = '<div class="empty">無 preamble 檔案</div>'; return; }
    const { content } = await r.json();
    panel.innerHTML = `<div class="preamble-view">${renderMarkdown(content)}</div>`;
  } catch { panel.innerHTML = '<div class="empty">載入失敗</div>'; }
}

async function loadHistory(name, panel) {
  try {
    const data = await fetch(`${API}/api/specialists/${encodeURIComponent(name)}/history`).then(r => r.json());
    if (data.length === 0) { panel.innerHTML = '<div class="empty">尚無歷史記錄</div>'; return; }
    let html = '<table class="history-table"><tr><th>Goal</th><th>Status</th><th>Turns</th><th>Time</th></tr>';
    data.forEach(t => {
      const statusIcon = t.status === 'done' ? '✅' : t.status === 'failed' ? '❌' : t.status === 'timeout' ? '⏰' : '🚫';
      html += `<tr>
        <td style="max-width:300px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${esc(t.goal)}">${esc(t.goal.slice(0, 60))}</td>
        <td>${statusIcon} ${t.verifier ? `(${t.verifier})` : ''}</td>
        <td>${t.turns ?? '-'}</td>
        <td>${t.elapsedSec}s</td>
      </tr>`;
    });
    html += '</table>';
    panel.innerHTML = html;
  } catch { panel.innerHTML = '<div class="empty">載入失敗</div>'; }
}

async function loadArtifacts(name, panel) {
  try {
    const data = await fetch(`${API}/api/specialists/${encodeURIComponent(name)}/artifacts`).then(r => r.json());
    if (data.length === 0) { panel.innerHTML = '<div class="empty">尚無產出物</div>'; return; }
    let html = '<div class="artifact-list">';
    data.forEach(a => {
      const sizeKb = (a.sizeBytes / 1024).toFixed(1);
      html += `<div class="artifact-item"><span>${esc(a.slug || a.filename)}</span><span>${a.date} · ${sizeKb}KB</span></div>`;
    });
    html += '</div>';
    panel.innerHTML = html;
  } catch { panel.innerHTML = '<div class="empty">載入失敗</div>'; }
}

async function loadFacts(name, panel) {
  try {
    const data = await fetch(`${API}/api/specialists/${encodeURIComponent(name)}/facts`).then(r => r.json());
    if (data.totalCount === 0) { panel.innerHTML = '<div class="empty">尚無相關 facts</div>'; return; }
    let html = `<div style="font-size:.8rem;margin-bottom:8px;color:var(--muted)">共 ${data.totalCount} 筆 facts</div>`;
    data.recentFacts.forEach(f => {
      html += `<div class="fact-item"><span class="fact-id">${esc(f.id)}</span> ${esc(f.text.slice(0, 120))}</div>`;
    });
    panel.innerHTML = html;
  } catch { panel.innerHTML = '<div class="empty">載入失敗</div>'; }
}

// ─── Live View ───────────────────────────────────────────────────────────────
function renderLiveView(taskId) {
  autoScroll = true;
  app.innerHTML = `
    <button class="back-btn" onclick="navigate('#/')">← Dashboard</button>
    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px">
      <h1 style="margin:0" id="liveTitle">${esc(taskId)}</h1>
      <button class="cancel-btn" id="liveCancel">取消</button>
    </div>
    <div class="live-view">
      <div class="live-body" id="liveBody"></div>
      <div class="live-footer">
        <span id="liveMeta"></span>
        <span id="liveStatus">connecting...</span>
      </div>
    </div>`;

  const liveBody = document.getElementById('liveBody');
  const liveStatus = document.getElementById('liveStatus');
  const liveMeta = document.getElementById('liveMeta');
  const liveTitle = document.getElementById('liveTitle');

  // Try to get task info for title
  fetch(`${API}/api/status/${encodeURIComponent(taskId)}`)
    .then(r => r.json())
    .then(t => {
      if (t && !t.error) liveTitle.textContent = t.specialist || t.peer || taskId;
    })
    .catch(() => {});

  eventSource = new EventSource(`${API}/api/status/${encodeURIComponent(taskId)}/stream`);
  eventSource.onmessage = (e) => {
    const msg = JSON.parse(e.data);
    if (msg.type === 'chunk') {
      const el = document.createElement('div');
      el.className = `chunk ${msg.role || 'agent'}`;
      el.textContent = msg.text;
      liveBody.appendChild(el);
      if (autoScroll) liveBody.scrollTop = liveBody.scrollHeight;
    } else if (msg.type === 'status') {
      liveStatus.textContent = msg.status;
      liveMeta.textContent = msg.turns ? `Turn ${msg.turns}` : '';
      if (msg.status !== 'running') {
        eventSource.close();
        eventSource = null;
      }
    }
  };
  eventSource.onerror = () => {
    liveStatus.textContent = 'disconnected';
    eventSource.close();
    eventSource = null;
  };

  liveBody.addEventListener('scroll', () => {
    autoScroll = liveBody.scrollHeight - liveBody.scrollTop - liveBody.clientHeight < 50;
  });

  document.getElementById('liveCancel').addEventListener('click', async () => {
    await fetch(`${API}/api/status/${encodeURIComponent(taskId)}/cancel`, { method: 'POST' });
    liveStatus.textContent = 'cancelled';
  });
}

// ─── Helpers ─────────────────────────────────────────────────────────────────
function esc(s) { return (s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;'); }

function renderMarkdown(md) {
  return esc(md)
    .replace(/^### (.+)$/gm, '<h3>$1</h3>')
    .replace(/^## (.+)$/gm, '<h2>$1</h2>')
    .replace(/^# (.+)$/gm, '<h1>$1</h1>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/`([^`]+)`/g, '<code>$1</code>')
    .replace(/^- (.+)$/gm, '• $1')
    .replace(/\n/g, '<br>');
}

function startPolling(fn) {
  stopPolling();
  pollTimer = setInterval(fn, 3000);
}

function stopPolling() {
  if (pollTimer) { clearInterval(pollTimer); pollTimer = null; }
}

// ─── Init ────────────────────────────────────────────────────────────────────
route();
</script>
</body>
</html>
```

