<script>
const API = location.origin;
const app = document.getElementById('app');
let pollTimer = null;
let currentRoute = null;
let eventSource = null;
let autoScroll = true;

// ─── Router ──────────────────────────────────────────────────────────────────
function navigate(hash) {
  location.hash = hash;
}

function getRoute() {
  const h = location.hash || '#/';
  const spMatch = h.match(/^#\/specialist\/(.+)$/);
  if (spMatch) return { page: 'specialist', name: decodeURIComponent(spMatch[1]) };
  const taskMatch = h.match(/^#\/task\/(.+)$/);
  if (taskMatch) return { page: 'task', taskId: decodeURIComponent(taskMatch[1]) };
  return { page: 'dashboard' };
}

window.addEventListener('hashchange', () => route());

function route() {
  stopPolling();
  if (eventSource) { eventSource.close(); eventSource = null; }
  const r = getRoute();
  currentRoute = r;
  if (r.page === 'dashboard') renderDashboard();
  else if (r.page === 'specialist') renderSpecialistDetail(r.name);
  else if (r.page === 'task') renderLiveView(r.taskId);
}

// ─── Dashboard ───────────────────────────────────────────────────────────────
async function renderDashboard() {
  app.innerHTML = '<div class="empty">載入中...</div>';
  try {
    const [statusRes, spRes] = await Promise.all([
      fetch(`${API}/api/status`).then(r => r.json()),
      fetch(`${API}/api/specialists`).then(r => r.json()),
    ]);
    paintDashboard(spRes, statusRes);
    startPolling(async () => {
      const [s, sp] = await Promise.all([
        fetch(`${API}/api/status`).then(r => r.json()),
        fetch(`${API}/api/specialists`).then(r => r.json()),
      ]);
      paintDashboard(sp, s);
    });
  } catch(e) {
    app.innerHTML = `<div class="empty">無法連線 API: ${esc(e.message)}</div>`;
  }
}

function paintDashboard(specialists, status) {
  let html = '';

  // Specialist cards
  html += '<div class="section-title">Specialists</div><div class="card-grid">';
  if (specialists.length === 0) {
    html += '<div class="empty">尚無 specialist 設定</div>';
  } else {
    html += specialists.map(sp => {
      const activeHtml = sp.activeTaskId
        ? `<div class="active-task" data-task="${esc(sp.activeTaskId)}">⚡ 執行中...</div>`
        : '';
      return `<div class="sp-card ${sp.status}" data-name="${esc(sp.name)}">
        <div class="name">${esc(sp.name)}</div>
        <div class="model">${esc(sp.model)}</div>
