```typescript
/**
 * /status command handler — shows active task status.
 * Opens web dashboard via Mini App button or fallback URL.
 */
import { Context } from "grammy";
import { listActiveTasks, listTasks, type TaskEntry } from "../status-store.js";
import { config } from "../config.js";
import { deps } from "./deps.js";

export async function handleStatus(ctx: Context): Promise<void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;

  const active = listActiveTasks();
  const statusUrl = `http://localhost:${config.statusPort}`;
  const httpsUrl = process.env.STATUS_HTTPS_URL?.trim();
  const webAppUrl = httpsUrl || statusUrl;

  // Build text summary
  let text: string;
  if (active.length === 0) {
    const recent = listTasks().filter((t) => t.status !== "running").slice(-5);
    if (recent.length === 0) {
      text = "目前沒有進行中或最近完成的任務。";
    } else {
      const lines = recent.map((t) => formatTaskLine(t));
      text = `目前沒有進行中的任務。\n\n最近完成：\n${lines.join("\n")}`;
    }
  } else {
    const lines = active.map((t) => formatTaskDetail(t));
    text = `⚡ ${active.length} 個任務進行中：\n\n${lines.join("\n\n")}`;
  }

  // Reply with Mini App button (HTTPS) or fallback text + URL
  if (httpsUrl) {
    await ctx.reply(text, {
      reply_markup: {
        inline_keyboard: [[
          { text: "🖥 開啟監控", web_app: { url: webAppUrl } },
        ]],
      },
    });
  } else {
    await ctx.reply(`${text}\n\n🔗 ${webAppUrl}`);
  }
}

function formatTaskDetail(t: TaskEntry): string {
  const elapsed = Math.round((Date.now() - new Date(t.startTime).getTime()) / 1000);
  const mins = Math.floor(elapsed / 60);
  const secs = elapsed % 60;
  const time = mins > 0 ? `${mins}m${secs}s` : `${secs}s`;
  const target = t.specialist ?? t.peer ?? "unknown";
  const turns = t.turns ? `Turn ${t.turns}` : "";
  const checkpoint = t.checkpoint?.currentStep ? `Step: ${t.checkpoint.currentStep}` : "";
  const lastOut = t.lastOutput ? `\n💬 ${t.lastOutput.slice(0, 100)}` : "";
  const info = [turns, checkpoint].filter(Boolean).join(" | ");
  return `🔄 [${target}] ${time}${info ? `\n📋 ${info}` : ""}\n🎯 ${t.goal.slice(0, 80)}${lastOut}`;
}

function formatTaskLine(t: TaskEntry): string {
  const icon = t.status === "running" ? "🔄" : t.status === "done" ? "✅" : t.status === "failed" ? "❌" : t.status === "timeout" ? "⏰" : "🚫";
  const elapsed = t.endTime
    ? Math.round((new Date(t.endTime).getTime() - new Date(t.startTime).getTime()) / 1000)
    : Math.round((Date.now() - new Date(t.startTime).getTime()) / 1000);
  const target = t.specialist ?? t.peer ?? "";
  const turns = t.turns ? ` T${t.turns}` : "";
  return `${icon} [${target}] ${t.goal.slice(0, 50)}${turns} (${elapsed}s)`;
}
```

