.live-body{flex:1;overflow-y:auto;padding:12px;font-family:'Courier New',monospace;font-size:.75rem;line-height:1.5;white-space:pre-wrap;word-break:break-all;background:var(--card);border-radius:8px}
.live-body .chunk{margin-bottom:2px}
.live-body .chunk.thought{color:#a78bfa}
.live-body .chunk.tool{color:var(--yellow)}
