    let html = '<div class="artifact-list">';
    data.forEach(a => { html += `<div class="artifact-item"><span>${esc(a.slug||a.filename)}</span><span>${a.date} · ${(a.sizeBytes/1024).toFixed(1)}KB</span></div>`; });
