    if (data.totalCount === 0) { panel.innerHTML = '<div class="empty">尚無相關 facts</div>'; return; }
    let html = `<div style="font-size:.8rem;margin-bottom:8px;color:var(--muted)">共 ${data.totalCount} 筆</div>`;
    data.recentFacts.forEach(f => { html += `<div class="fact-item"><span class="fact-id">${esc(f.id)}</span> ${esc(f.text.slice(0,120))}</div>`; });
